mapper.select:
SELECT a.*, u.username, u.real_name, p.name AS pet_name, p.image AS pet_image, p.breed AS pet_breed FROM adoption a LEFT JOIN user u ON a.user_id = u.id LEFT JOIN pet p ON a.pet_id = p.id
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR p.name LIKE CONCAT('%', #{keyword}, '%'))
AND a.status = #{status}
ORDER BY a.apply_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM adoption a LEFT JOIN user u ON a.user_id = u.id LEFT JOIN pet p ON a.pet_id = p.id
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR p.name LIKE CONCAT('%', #{keyword}, '%'))
AND a.status = #{status}

mapper.update:
UPDATE adoption
status = #{status}, approve_time = #{approveTime},
WHERE id = #{id}

mapper.select:
SELECT MONTH(apply_time) AS month, COUNT(*) AS count
FROM adoption WHERE YEAR(apply_time) = #{year}
GROUP BY MONTH(apply_time) ORDER BY month
